@strawberry.type
class Product:
    id: strawberry.ID
    sku: str
    name: str
    description: Optional[str]

    @strawberry.field
    def reviews(self, info: Info) -> List[Review]:
        m: ProductModel = info.context["product_model"]
        return [Review(id=str(r.id), rating=r.rating, title=r.title, body=r.body) for r in m.reviews]

    @strawberry.field
    def sellers(self, info: Info) -> List[Seller]:
        m: ProductModel = info.context["product_model"]
        return [Seller(id=str(s.id), name=s.name) for s in m.sellers]

    @strawberry.field
    def categories(self, info: Info) -> List[Category]:
        m: ProductModel = info.context["product_model"]
        return [Category(id=str(c.id), name=c.name) for c in m.categories]

    @strawberry.field
    def images(self, info: Info) -> List[Image]:
        m: ProductModel = info.context["product_model"]
        return [Image(id=str(i.id), url=i.url, alt_text=i.alt_text) for i in m.images]


def _product_from_model(m: ProductModel) -> Product:
    return Product(id=str(m.id), sku=m.sku, name=m.name, description=m.description)


def get_db_session() -> Session:
    return SessionLocal()


def get_context() -> dict:
    return {"db": get_db_session()}


@strawberry.type
class Query:
    @strawberry.field
    def product(self, info: Info, id: Optional[strawberry.ID] = None, sku: Optional[str] = None) -> Optional[Product]:
        db: Session = info.context["db"]
        q = db.query(ProductModel).options(
            selectinload(ProductModel.reviews),
            selectinload(ProductModel.images),
            selectinload(ProductModel.categories),
            selectinload(ProductModel.sellers),
        )
        m: Optional[ProductModel] = None
        if id is not None:
            m = q.filter(ProductModel.id == int(str(id))).first()
        elif sku is not None:
            m = q.filter(ProductModel.sku == sku).first()
        else:
            return None
        if not m:
            return None
        info.context["product_model"] = m
        return _product_from_model(m)

    @strawberry.field
    def products(
        self,
        info: Info,
        search: Optional[str] = None,
        category: Optional[str] = None,
        seller: Optional[str] = None,
        limit: Optional[int] = None,
        offset: Optional[int] = None,
    ) -> List[Product]:
        db: Session = info.context["db"]
        q = db.query(ProductModel).options(
            selectinload(ProductModel.reviews),
            selectinload(ProductModel.images),
            selectinload(ProductModel.categories),
            selectinload(ProductModel.sellers),
        )

        if search:
            like = f"%{search}%"
            q = q.filter((ProductModel.name.ilike(like)) | (ProductModel.description.ilike(like)) | (ProductModel.sku.ilike(like)))

        if category:
            q = q.join(ProductModel.categories).filter(CategoryModel.name == category)

        if seller:
            q = q.join(ProductModel.sellers).filter(SellerModel.name == seller)

        if offset:
            q = q.offset(offset)
        if limit:
            q = q.limit(limit)

        ms = q.all()
        out: List[Product] = []
        for m in ms:
            info.context["product_model"] = m
            out.append(_product_from_model(m))
        return out

    @strawberry.field
    def categories(self, info: Info) -> List[Category]:
        db: Session = info.context["db"]
        ms = db.query(CategoryModel).order_by(CategoryModel.name.asc()).all()
        return [Category(id=str(m.id), name=m.name) for m in ms]

    @strawberry.field
    def sellers(self, info: Info) -> List[Seller]:
        db: Session = info.context["db"]
        ms = db.query(SellerModel).order_by(SellerModel.name.asc()).all()
        return [Seller(id=str(m.id), name=m.name) for m in ms]


schema = strawberry.Schema(query=Query)

